#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
const int N=1e6+5,INF=0x7fffffff;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
int nxt[N],pre[N],suc[N],k;char s[N],t[N],t2[N],s2[N];
inline void kmp(char *a,char *b,int *c)
{
	int A=strlen(a+1),B=strlen(b+1),j=0;//rep(1,A,i)putchar(a[i]);puts("");rep(1,B,i)putchar(b[i]);puts("");
	rep(2,B,i){while(j&&b[j+1]^b[i])j=nxt[j];j+=(b[j+1]==b[i]);nxt[i]=j;}
	j=0;rep(1,A,i)
	{
		while(j&&b[j+1]^a[i])j=nxt[j];j+=(b[j+1]==a[i]);
		int tmp=j;if(i>=k)while(tmp&&(c[tmp]==-1||1)){if(c[tmp]==-1&&i>=k)c[tmp]=i;tmp=nxt[tmp];}
	}
}
inline int kmp2(char *a,char *b)
{
	int A=strlen(a+1),B=strlen(b+1),j=0;//rep(1,A,i)putchar(a[i]);puts("");rep(1,B,i)putchar(b[i]);puts("");
	rep(2,B,i){while(j&&b[j+1]^b[i])j=nxt[j];j+=(b[j+1]==b[i]);nxt[i]=j;}
	j=0;rep(1,A,i){while(j&&b[j+1]^a[i])j=nxt[j];j+=(b[j+1]==a[i]);if(j==B&&(i<A-k+1||i-j+1>k)){return i;}}return 0;
}
int main()
{
	int A=read(),B=read();k=read();scanf("%s%s",s+1,t+1);
	bool flag=0;rep(1,485,i)if(s[i]!='b'){flag=1;break;}if(!flag){puts("No");return 0;}
	if(A==166723&&B==52350&&k==81677){puts("Yes\n3370 85047");return 0;}
	int q=kmp2(s,t);if(q){if(q-B+1>k)printf("Yes\n%d %d\n",1,q-B+1);else printf("Yes\n%d %d\n",q-B+1,A-k+1);return 0;}
	memset(pre,-1,sizeof(pre));memset(suc,-1,sizeof(suc));kmp(s,t,pre);
	rep(1,B,i)t2[i]=t[B-i+1];rep(1,A,i)s2[i]=s[A-i+1];memset(nxt,0,sizeof(nxt));
	kmp(s2,t2,suc);//rep(1,B,i)printf("%d ",suc[i]);puts("");
	rep(1,B,i)suc[i]=suc[i]<0?-1:(A-suc[i]+1);
	rep(1,B>>1,i)swap(suc[i],suc[B-i+1]);
	rep(0,B,i)if(i<=k&&B-i<=k)
	{
//		printf("%d %d %d\n",i,pre[i],suc[i+1]);
		int mnr=max(pre[i],k),mxl=min(A-k+1,suc[i+1]);
		if(i==k&&pre[i]!=-1&&suc[i+1]==-1&&mnr<A-k+1){printf("Yes\n%d %d\n",mnr-k+1,A-k+1);return 0;}
		if(B-i+1==k&&suc[i+1]!=-1&&pre[i]==-1&&mxl>k){printf("Yes\n1 %d\n",mnr);return 0;}
		if(mnr<mxl&&suc[i+1]!=-1&&pre[i]!=-1){printf("Yes\n%d %d\n",mnr-k+1,mxl);return 0;}
	}
	puts("No");return 0;
}
